import React, { useState } from 'react';

function App() {
  const [buttonText, setButtonText] = useState('Click me');

  const handleClick = () => {
    setButtonText('Button clicked!');
  };

  return (
    <div className="App">
      <h1>Fun Button</h1>
      <button onClick={handleClick}>{buttonText}</button>
    </div>
  );
}

export default App;
